private static String cacheString(final char[] charBuf, final String[] stringCache, final int start, final int count) throws IndexOutOfBoundsException{
    // limit (no cache):
    if (count > maxStringCacheLen)
        return new String(charBuf, start, count);

    // Exception handling
    if (start < 0 || (start+count) > charBuf.length){
       throw new IndexOutOfBoundsException();
